        "-bool NetworkLayer::SendToPlayer(const std::vector<uint8_t>& frame, uint32_t playerId) {",
        "-    if (!udp_ || frame.empty() || !isServer_) return false;",
        "-",
        "-    // Look up the endpoint for this playerId",
