        "-        }",
        "-    }",
        "-",
        "-    // Enqueue for Receive()",
        "-    {",
        "-        std::lock_guard<std::mutex> lock(recvMutex_);",
        "-        recvQueue_.push_back(std::move(msg));",
        "-    }",
        "-    msgsRcvd_++;",
        "-",
        "-    // Invoke callback",
        "-    if (onMessage_) {",
        "-        onMessage_(data, len);",
        "-    }",
        "-}",
